-- ============================================================
-- Aurora 4x 日本人指揮官 名漢字化SQL
-- DIM_CommanderNames NameThemeID=8（日本語テーマ）の
-- FirstName エントリをローマ字から漢字に置き換えます
-- 元の件数（689件）を維持
-- Female=0: 男性名 / Female=1: 女性名
-- 何度実行しても同じ結果になります（冪等性）
-- ============================================================

DELETE FROM DIM_CommanderNames WHERE NameThemeID=8 AND FirstName=1;

